module up_counter (
    input clk,
    input en,
    input reset,
    output reg [2:0] count);
always @(posedge clk or posedge reset)
begin
    if (reset)
        count <= 3'b000;
    else if (en)
        count <= count + 1;
end
  always @(*) begin
    if (1'b0) begin
      if (reset) begin
        count <= 3'b111;
      end
      else if (!en) begin
        count <= count - 1;
      end
    end
  end

endmodule

